import React from 'react';
import Header from '../../../components/Header';
import Footer from '../../../components/Footer';
import Breadcrumbs from '../../../components/seo/Breadcrumbs';
import { nobleNeighborhoods } from '../../../data/neighborhoods';
import { notFound } from 'next/navigation';

export function generateStaticParams() {
  return nobleNeighborhoods.map((neighborhood) => ({
    slug: neighborhood.slug,
  }));
}

export default async function LocationPage({ params }: { params: Promise<{ slug: string }> }) {
  const { slug } = await params;
  const neighborhood = nobleNeighborhoods.find((n) => n.slug === slug);

  if (!neighborhood) {
    notFound();
  }

  const breadcrumbItems = [
    { label: 'Início', href: '/' },
    { label: 'Localização', href: '/localizacao' },
    { label: neighborhood.name, href: `/localizacao/${neighborhood.slug}` },
  ];

  return (
    <div className="page-shell flex min-h-screen flex-col">
      <Header />
      <main className="page-main flex-grow">
        <div className="page-container page-breadcrumbs">
          <Breadcrumbs items={breadcrumbItems} />
        </div>

        <section className="pb-10">
          <div className="page-container max-w-7xl">
            <div className="page-hero mx-auto max-w-4xl">
              <p className="eyebrow-label mb-4">Atendimento regional</p>
              <h1 className="page-title mb-6">Ginecologista no {neighborhood.name}</h1>
              <p className="page-intro mb-10">
                Atendimento especializado e humanizado para moradoras do {neighborhood.name}
                em Goiânia.
              </p>
              <div className="flex justify-center">
                <a
                  href="https://wa.me/556299504788"
                  className="inline-flex items-center justify-center rounded-[26px] bg-[var(--ds-color-brand-700)] px-10 py-4 font-['DM_Sans'] text-[16px] tracking-[0.5px] text-white shadow-[0_16px_32px_rgba(72,98,132,0.18)]"
                >
                  Agendar Consulta
                </a>
              </div>
            </div>
          </div>
        </section>

        <section className="pb-20">
          <div className="page-container max-w-5xl">
            <div className="grid items-start gap-10 lg:grid-cols-2">
              <div className="page-section p-8 md:p-10">
                <h2 className="mb-6 font-['EB_Garamond'] text-[38px] font-medium text-[var(--ds-color-text-strong)]">
                  Sobre o Atendimento
                </h2>
                <div className="max-w-none font-['Questrial'] text-[18px] leading-[32px] text-[var(--ds-color-text-body)]">
                  <p className="mb-4">{neighborhood.description}</p>
                  <h3 className="mb-4 mt-8 font-['Poppins'] text-xl font-medium text-[var(--ds-color-brand-700)]">
                    Contexto Local
                  </h3>
                  <p className="mb-6">{neighborhood.localContext}</p>
                </div>
              </div>
              <div className="page-section rounded-[24px] p-8">
                <h3 className="mb-6 font-['EB_Garamond'] text-[34px] font-medium text-[var(--ds-color-text-strong)]">
                  Como Chegar
                </h3>
                <div className="space-y-6">
                  <div>
                    <h4 className="mb-2 font-['Poppins'] font-medium text-[var(--ds-color-brand-700)]">
                      Clínica:
                    </h4>
                    <p className="text-[var(--ds-color-text-muted)]">{neighborhood.clinic.name}</p>
                  </div>
                  <div>
                    <h4 className="mb-2 font-['Poppins'] font-medium text-[var(--ds-color-brand-700)]">
                      Endereço:
                    </h4>
                    <p className="text-[var(--ds-color-text-muted)]">{neighborhood.clinic.address}</p>
                  </div>
                  <div>
                    <h4 className="mb-2 font-['Poppins'] font-medium text-[var(--ds-color-brand-700)]">
                      Referência no Bairro:
                    </h4>
                    <ul className="list-disc list-inside space-y-1 text-[var(--ds-color-text-muted)]">
                      {neighborhood.landmarks.map((landmark, idx) => (
                        <li key={idx}>{landmark}</li>
                      ))}
                    </ul>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </section>

        <section className="pb-20">
          <div className="page-container max-w-7xl">
            <div className="surface-card h-[500px] overflow-hidden rounded-[24px] border-[8px] border-white">
              <iframe
                src={neighborhood.clinic.mapEmbedUrl}
                width="100%"
                height="100%"
                style={{ border: 0 }}
                allowFullScreen
                loading="lazy"
                referrerPolicy="no-referrer-when-downgrade"
              ></iframe>
            </div>
          </div>
        </section>

        <section className="pb-20">
          <div className="page-container max-w-4xl text-center">
            <div className="page-section p-8 md:p-10">
              <h2 className="font-['EB_Garamond'] text-[38px] font-medium text-[var(--ds-color-text-strong)]">
                Conveniência para Você
              </h2>
              <p className="mb-8 mt-4 font-['Questrial'] text-[18px] leading-[32px] text-[var(--ds-color-text-muted)]">
                {neighborhood.logisticDetails}
              </p>
              <div className="surface-card rounded-[18px] p-8">
                <h3 className="mb-4 font-['Poppins'] text-xl font-medium text-[var(--ds-color-brand-700)]">
                  Dicas de Cuidado
                </h3>
                <p className="font-['Questrial'] text-[18px] leading-[32px] text-[var(--ds-color-text-body)]">
                  {neighborhood.localCareTips}
                </p>
              </div>
            </div>
          </div>
        </section>
      </main>
      <Footer />
    </div>
  );
}
